const express = require('express');
const redis = require('redis');
const twilio = require('twilio')(accountSid, authToken);

const app = express();
const client = redis.createClient();

app.use((req, res, next) => {
  const userId = req.query.userId;
  const code = req.body.code;
  if (code === null || code === undefined) {
    return res.status(400).send('Code is required');
  }

  client.get(`${userId}-code`, (err, storedCode) => {
    if (err) {
      console.error(err);
      return res.status(500).send('Internal server error');
    }

    if (storedCode === null || storedCode === undefined) {
      return res.status(403).send('Invalid code');
    }

    const expiration = Math.floor(Date.now() / 1000);
    const expired = expiration - parseInt(storedCode, 10) > 600;

    if (expired) {
      return res.status(403).send('Code has expired');
    }

    if (code === storedCode) {
      client.del(`${userId}-code`, () => {
        res.json({ message: 'Success' });
      });
    } else {
      client.incrby(`${userId}-attempts`, 1);
      const attempts = parseInt(client.get(`${userId}-attempts`), 10);
      if (attempts > 10) {
        client.del(`${userId}-code`);
        return res.status(429).send('Too many attempts, please try again later');
      } else {
        return res.status(403).send('Invalid code');
      }
    }
  });
});

app.post('/auth', (req, res) => {
  const userId = req.body.userId;
  const code = req.body.code;

  client.set(`${userId}-code`, Math.floor(Math.random() * 10 ** 6).toString());

  twilio.messages.create({
    to: `+1 ${req.body.phone}`,
    from: '+123456789',
    body: `Your code is ${client.get(`${userId}-code`)}`
  }, (err, message) => {
    if (err) {
      console.error(err);
      return res.status(500).send('Internal server error');
    }

    res.json({ message: 'Code sent' });
  });
});